func:
try {
    var d = JSON.parse(msg.payload);
    var v = parseFloat(d.value);
    if (isNaN(v)) return null;
    global.set('last_temp', v);
    msg.payload = v;
    msg.topic = 'Temperature';
    return msg;
} catch(e) { return null; }

var thr = global.get('thr_temp') || 30;
if (msg.payload > thr) {
    msg.payload = 'HIGH TEMPERATURE: ' + msg.payload.toFixed(1) + '°C';
    msg.topic = new Date().toLocaleTimeString();
    return msg;
}
return null;

try {
    var d = JSON.parse(msg.payload);
    var v = parseFloat(d.value);
    if (isNaN(v)) return null;
    global.set('last_hum', v);
    msg.payload = v;
    msg.topic = 'Humidity';
    return msg;
} catch(e) { return null; }

try {
    var d = JSON.parse(msg.payload);
    var v = parseInt(d.value);
    if (isNaN(v)) return null;
    global.set('last_light', v);
    msg.payload = v;
    return msg;
} catch(e) { return null; }

var thr = global.get('thr_light') || 2000;
if (msg.payload < thr) {
    msg.payload = ' LOW LIGHT: ' + msg.payload;
    msg.topic = new Date().toLocaleTimeString();
    return msg;
}
return null;

// Lab 4: parse JSON payload from ESP32
// Assignment topic: sensors/motion  payload: {detected: true/false}
try {
    var d = JSON.parse(msg.payload);
    global.set('last_motion', d.detected);
    if (d.detected) {
        node.send([
            { payload: ' Motion Detected' },
            { payload: ' MOTION DETECTED', topic: new Date().toLocaleTimeString() }
        ]);
    } else {
        node.send([{ payload: ' No Motion' }, null]);
    }
} catch(e) {}

try {
    var d = JSON.parse(msg.payload);
    var v = parseFloat(d.value);
    if (isNaN(v)) return null;
    global.set('last_dist', v);
    msg.payload = v;
    return msg;
} catch(e) { return null; }

var thr = global.get('thr_dist') || 20;
if (msg.payload < thr) {
    msg.payload = 'OBJECT TOO CLOSE: ' + msg.payload.toFixed(1) + ' cm';
    msg.topic = new Date().toLocaleTimeString();
    return msg;
}
return null;

var temp   = global.get('last_temp');
var light  = global.get('last_light');
var motion = global.get('last_motion') || false;
var dist   = global.get('last_dist');
var thr_t  = global.get('thr_temp')   || 30;
var thr_l  = global.get('thr_light')  || 2000;
var thr_d  = global.get('thr_dist')   || 20;

if (temp === null || temp === undefined) return null;
if (light === null || light === undefined) light = 9999;
if (dist === null || dist === undefined) dist = 9999;

var allOk = (temp <= thr_t) && (light >= thr_l) && !motion && (dist >= thr_d);
msg.payload = JSON.stringify({ state: allOk ? 'on' : 'off', color: 'green' });
return msg;

var log = global.get('alert_log') || [];
log.unshift({ Time: msg.topic || new Date().toLocaleTimeString(), Message: msg.payload });
if (log.length > 50) log = log.slice(0, 50);
global.set('alert_log', log);
msg.payload = log;
return msg;

var token  = (global.get('tg_token') || '').trim();
var chatId = (global.get('tg_chat')  || '').trim();
if (!token || !chatId) return null;


var key  = 'tg_cd_' + msg.payload.replace(/[^A-Z]/g, '').substring(0, 12);
var last = global.get(key) || 0;
if (Date.now() - last < 60000) return null;
global.set(key, Date.now());

msg.url     = 'https://api.telegram.org/bot' + token + '/sendMessage';
msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    chat_id: chatId,
    text: 'SmartEnv Alert\n' + msg.payload + '\n' + new Date().toLocaleTimeString()
});
return msg;

var token  = (global.get('tg_token') || '').trim();
var chatId = (global.get('tg_chat')  || '').trim();
if (!token || !chatId) {
    node.warn('Set Bot Token and Chat ID first');
    return null;
}
msg.url     = 'https://api.telegram.org/bot' + token + '/sendMessage';
msg.method  = 'POST';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = JSON.stringify({
    chat_id: chatId,
    text: 'SmartEnv Test\nTelegram is working!\n' + new Date().toLocaleTimeString()
});
return msg;

var t = (msg.payload || '').trim();
if (t) global.set('tg_token', t);
return null;

var c = (msg.payload || '').trim();
if (c) global.set('tg_chat', c);
return null;

global.set('thr_temp', msg.payload);
msg.payload = JSON.stringify({
    temp_max:  msg.payload,
    light_min: global.get('thr_light') || 2000,
    dist_min:  global.get('thr_dist')  || 20
});
return msg;

global.set('thr_light', msg.payload);
msg.payload = JSON.stringify({
    temp_max:  global.get('thr_temp')  || 30,
    light_min: msg.payload,
    dist_min:  global.get('thr_dist')  || 20
});
return msg;

global.set('thr_dist', msg.payload);
msg.payload = JSON.stringify({
    temp_max:  global.get('thr_temp')  || 30,
    light_min: global.get('thr_light') || 2000,
    dist_min:  msg.payload
});
return msg;

try {
    var d = JSON.parse(msg.payload);
    msg.payload = 'Uptime: ' + d.uptime + 's   |   RSSI: ' + d.rssi + ' dBm   |   Free Heap: ' + d.free_memory + ' bytes';
    return msg;
} catch(e) { return null; }

var last = global.get('last_heartbeat') || 0;
var diff = Date.now() - last;
if (last === 0) {
    msg.payload = 'Waiting for ESP32...';
} else if (diff > 30000) {
    msg.payload = 'ESP32 OFFLINE — No heartbeat for ' + Math.round(diff / 1000) + 's';
} else {
    msg.payload = 'ESP32 Online — Last seen ' + Math.round(diff / 1000) + 's ago';
}
return msg;

node.send([
    { payload: 'Waiting for ESP32 heartbeat...' },
    { payload: 'Waiting for ESP32...' }
]);

var log   = global.get('sensor_log') || [];
var isNew = log.length === 0;
var entry = {
    ts:     Date.now(),
    time:   new Date().toISOString(),
    temp:   global.get('last_temp')   || 0,
    hum:    global.get('last_hum')    || 0,
    light:  global.get('last_light')  || 0,
    motion: global.get('last_motion') || false,
    dist:   global.get('last_dist')   || 0
};
log.push(entry);

log = log.filter(function(r) { return r.ts > Date.now() - 86400000; });
global.set('sensor_log', log);

var row = entry.time + ',' + entry.temp + ',' + entry.hum + ',' +
          entry.light + ',' + entry.motion + ',' + entry.dist + '\n';
if (isNew) {
    msg.payload  = 'Timestamp,Temp_C,Humidity_pct,Light_raw,Motion,Distance_cm\n' + row;
    msg.overwrite = true;
} else {
    msg.payload   = row;
    msg.overwrite = false;
}
return msg;

var hours  = parseInt(msg.req.query.hours) || 24;
var cutoff = Date.now() - hours * 3600000;
var log    = global.get('sensor_log') || [];
var rows   = log.filter(function(r) { return r.ts >= cutoff; });
var csv    = 'Timestamp,Temp_C,Humidity_pct,Light_raw,Motion,Distance_cm\n';
rows.forEach(function(r) {
    csv += r.time + ',' + r.temp + ',' + r.hum + ',' +
           r.light + ',' + r.motion + ',' + r.dist + '\n';
});
msg.payload = csv;
msg.headers = {
    'Content-Type': 'text/csv',
    'Content-Disposition': 'attachment; filename="smartenv_' + hours + 'h.csv"'
};
return msg;

var hours  = parseInt(msg.payload) || 1;
var cutoff = Date.now() - hours * 3600000;
var log    = global.get('sensor_log') || [];
var rows   = log.filter(function(r) { return r.ts >= cutoff; });

node.send({ payload: [], topic: 'Temperature' });
node.send({ payload: [], topic: 'Humidity' });

rows.forEach(function(r) {
    node.send({ payload: r.temp, topic: 'Temperature', x: r.ts });
});
rows.forEach(function(r) {
    node.send({ payload: r.hum,  topic: 'Humidity',    x: r.ts });
});
return null;
